<template >
  <div class="container">
    <div class="row g-4 text-center d-flex align-items-center justify-content-center ">
        <h3 class="mt-5" >{{ categoryName }}</h3>
            <template v-if="!isLoading" >
              <div v-for="i in 20" :key="i"   class="col12 col-md-4 ">
                <div class="card">
                  <div class="card-text w-100 img-thumbnail skeleton " style="width:300px; height: 250px;">
                  </div>
                  <div class="card-body">
                    <div class="skeleton skeleton-text "></div>
                    <div class="skeleton skeleton-text "></div>
                  </div>
                </div>
              </div>
            </template>
            <template v-if="isLoading">
              <div  v-for="p in products" :key="p.id"  class="col-12 col-md-4   ">
                    <router-link :to="`/productdetail?productid=${p.id}`">
                      <div  class="card hover-zoom bg-transparent ">
                        <img  :src="p.productImg" class="card-img-top w-100 img-thumbnail " style="width:300px; height: 250px;" alt="...">
                        <div class="card-body text-center">
                          <p class="card-text">{{p.productName}}</p>
                          <p class="card-text">{{p.productDesc }}</p>
                        </div>
                      </div>
                    </router-link> 
              </div>
            </template>  
          
    </div>
  </div>
</template>

<script>
import {onBeforeMount,watch,ref } from 'vue'
import { useRoute} from 'vue-router'
import axios from 'axios';

export default {
  name:'ProductShow',
  setup(){
  let route= useRoute();
  let categoryName=ref(route.params.cid);
  let isLoading =ref(false)
  let products=ref([])
  
  onBeforeMount(() => {
    isLoading.value=false
    axios.get(`/getproducts?category=${categoryName.value}`).then(
      response =>{
        console.log('請求成功',response.data)
        products.value=response.data
        console.log(products.value)
        isLoading.value=true
      }
    ).catch(
      error =>{
        console.log(error.message,'請求失敗')
      }
    )
  }),


  // 透過watch屬性監聽路由參數變動，太神啦！！
  watch(()=>route.params.cid,(newValue)=>{
    categoryName.value=newValue
    axios.get(`/getproducts?category=${categoryName.value}`).then(
      response =>{
        console.log('請求成功',response.data)
        products.value=response.data
        isLoading.value=true
        console.log(products.value)
      }
    ).catch(
      error =>{
        console.log(error.message,'請求失敗')
      }
    )
  })
  
  return{
    categoryName,
    products,
    isLoading
  }
  },
}


</script>

